#include<bits/stdc++.h>
using namespace std;
const long long mod=998244353;
long long fz=1,fm=1,n,m,k,a,d,x;
long long inv(long long x,long long y=mod-2)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y>>=1;
    }
    return ans;
}
int main()
{
    scanf("%lld%lld%lld",&n,&m,&k);
    if(k)
    {
        scanf("%lld%lld%lld",&a,&d,&x);
    }
    for(long long i=1;i<k;i++)
    {
        a=(a-d)^x;
    }
    long long c=0;
    for(long long i=0;i<k;i++)
    {
        if(a<=n)
        {
            fm=fm*(a-c)%mod;
            c=a-1;
        }
        else
        {
            fz=fz*(a-n)%mod;
            fm=fm*(a-c)%mod;
            break;
        }
        a=(a^x)+d;
    }
    if(a<=n)
    {
        fz=fz*m%mod;
        fm=fm*(m+n-c)%mod;
    }
    printf("%lld",(1-fz*inv(fm)%mod+mod)%mod);
    return 0;
}
